import okhttp3.Interceptor
import okhttp3.OkHttpClient
import okhttp3.Response
import retrofit2.Retrofit
import retrofit2.converter.gson.GsonConverterFactory

object NetworkManager {
    private const val BASE_URL_DEV = "https://api.example.com/dev/"
    private const val BASE_URL_STAGING = "https://api.example.com/staging/"
    private const val BASE_URL_PROD = "https://api.example.com/prod/"

    fun createApiService(environment: String, authToken: String): UserService {
        val baseUrl = when (environment) {
            "dev" -> BASE_URL_DEV
            "staging" -> BASE_URL_STAGING
            "prod" -> BASE_URL_PROD
            else -> throw IllegalArgumentException("Unknown environment")
        }

        val client = OkHttpClient.Builder()
            .addInterceptor { chain ->
                val requestBuilder = chain.request().newBuilder()
                    .header("Authorization", "Bearer $authToken")
                chain.proceed(requestBuilder.build())
            }
            .build()

        val retrofit = Retrofit.Builder()
            .baseUrl(baseUrl)
            .client(client)
            .addConverterFactory(GsonConverterFactory.create())
            .build()

        return retrofit.create(UserService::class.java)
    }
}

interface UserService {
    @GET("users")
    suspend fun getUsers(): List<User>
}

data class User(
    val id: Int,
    val name: String,
    val email: String
)

